def vols(self, indices=None) -> List[DenseNeuroVol]:
    """Extract volumes as list.

    R Equivalent
    ------------
    neuroim2::vols
    """
    if indices is None:
        indices = range(self.shape[3])
    elif isinstance(indices, int):
        indices = [indices]

    return [self[..., i] for i in indices]

